import React from "react";
import { Select, Input } from "antd";
import { Bell, Download, Search } from "lucide-react";

// Helper function to get time-based greeting
const getGreeting = () => {
  const hour = new Date().getHours();
  if (hour >= 5 && hour < 12) {
    return "Chào buổi sáng! 🌤️";
  } else if (hour >= 12 && hour < 18) {
    return "Chào buổi trưa! ☀️";
  } else if (hour >= 18 && hour < 21) {
    return "Chào buổi chiều! 🌅";
  } else {
    return "Chào buổi tối! 🌙";
  }
};

// Helper function to get Vietnamese day name
const getVietnameseDay = (dayIndex) => {
  const days = ["Chủ Nhật", "Thứ Hai", "Thứ Ba", "Thứ Tư", "Thứ Năm", "Thứ Sáu", "Thứ Bảy"];
  return days[dayIndex];
};

// Helper function to get Vietnamese month name
const getVietnameseMonth = (monthIndex) => {
  const months = [
    "tháng 1", "tháng 2", "tháng 3", "tháng 4", "tháng 5", "tháng 6",
    "tháng 7", "tháng 8", "tháng 9", "tháng 10", "tháng 11", "tháng 12"
  ];
  return months[monthIndex];
};

// Helper function to format date in Vietnamese
const formatDateVietnamese = () => {
  const now = new Date();
  const dayName = getVietnameseDay(now.getDay());
  const day = now.getDate();
  const month = getVietnameseMonth(now.getMonth());
  const year = now.getFullYear();
  return `${dayName}, ${day} ${month} năm ${year}`;
};

// Helper function to get motivational tagline based on time of day
const getMotivationalTagline = () => {
  const hour = new Date().getHours();
  if (hour >= 5 && hour < 12) {
    return "Cùng nhau bắt đầu ngày mới nào!";
  } else if (hour >= 12 && hour < 14) {
    return "Giờ nghỉ trưa thư giãn một chút nhé!";
  } else if (hour >= 14 && hour < 18) {
    return "Chiều này cố gắng hết sức nhé!";
  } else if (hour >= 18 && hour < 21) {
    return "Chúc bạn buổi tối thật vui vẻ!";
  } else {
    return "Nghỉ ngơi ngon giấc nhé!";
  }
};

const DashboardHeader = () => {
  const greeting = getGreeting();
  const dateVietnamese = formatDateVietnamese();
  const tagline = getMotivationalTagline();

  return (
    <div className="dashboard-content-header">
      <div className="dashboard-title-section">
        <h1 className="dashboard-content-title">{greeting}</h1>
        <p className="dashboard-content-date">{dateVietnamese}</p>
        <p className="dashboard-content-tagline">{tagline}</p>
      </div>

      <div className="dashboard-content-controls">
        <Select
          defaultValue="hanoi"
          style={{ width: 160 }}
          size="middle"
          options={[
            { value: "hanoi", label: "Hà Nội" },
            { value: "hcm", label: "Hồ Chí Minh" },
            { value: "danang", label: "Đà Nẵng" },
          ]}
        />
        <Select
          defaultValue="t6t8"
          style={{ width: 150 }}
          size="middle"
          options={[
            { value: "t6t8", label: "T6 - T8/2026" },
            { value: "t1t3", label: "T1 - T3/2026" },
            { value: "t4t6", label: "T4 - T6/2026" },
            { value: "t9t12", label: "T9 - T12/2026" },
          ]}
        />
        <button className="export-btn" title="Xuất dữ liệu">
          <Download size={16} strokeWidth={2} />
        </button>
      </div>
    </div>
  );
};

export default DashboardHeader;

